def is_multiply_prime(a):
    """Write a function that returns true if the given number is the multiplication of 3 prime numbers
    and false otherwise.
    Knowing that (a) is less then 100. 
    Example:
    is_multiply_prime(30) == True
    30 = 2 * 3 * 5
    """
    if a < 8:  # smallest product of 3 primes is 2*2*2=8
        return False

    # Find all prime factors of a
    def get_prime_factors(n):
        factors = []
        d = 2
        while d * d <= n:
            while n % d == 0:
                factors.append(d)
                n //= d
            d += 1
        if n > 1:
            factors.append(n)
        return factors

    factors = get_prime_factors(a)

    # Check if there are exactly 3 prime factors (counting multiplicity)
    if len(factors) != 3:
        return False

    # Check if all factors are prime (they should be by construction, but let's verify)
    def is_prime(n):
        if n < 2:
            return False
        if n == 2:
            return True
        if n % 2 == 0:
            return False
        for i in range(3, int(n**0.5) + 1, 2):
            if n % i == 0:
                return False
        return True

    for f in factors:
        if not is_prime(f):
            return False

    return True
